package render

import (
	"fmt"
	"io"
	"sort"
	"strings"
)

// Node is a renderable graph node carrying full provenance: identity, kind,
// qualified name, source coordinates, and optional extra metadata. Every
// rendering primitive operates on this shape, so its field set and ordering are
// load-bearing for the whole rendering surface; reordering fields reshapes every
// serialized output and every caller's struct literal.
type Node struct {
	ID            string
	Kind          string
	QualifiedName string
	SourcePath    string
	Line          int
	Column        int
	Extra         map[string]string
}

// Validate reports whether a node has the identity fields a renderer requires.
// Renderers call it before emitting to produce a single, precise error rather
// than a partial line followed by a format failure.
func (n Node) Validate() error {
	if n.ID == "" {
		return fmt.Errorf("render: empty node id")
	}
	if n.Kind == "" {
		return fmt.Errorf("render: empty node kind")
	}
	return nil
}

// RenderNode writes a single node and its neighborhood to w as one line. It is
// the central rendering primitive: every higher-level renderer composes output
// on top of it, so its signature, field order, and error contract are load-
// bearing for the whole surface. Changing it forces every caller to adapt.
func RenderNode(w io.Writer, n Node) error {
	if err := n.Validate(); err != nil {
		return err
	}
	if _, err := fmt.Fprintf(w, "%s %s @ %s:%d:%d\n", n.Kind, n.QualifiedName, n.SourcePath, n.Line, n.Column); err != nil {
		return err
	}
	return nil
}

// RenderTree renders a root node followed by its children, delegating per-node
// output to RenderNode. It is one of the production callers of RenderNode and
// the main entry point for hierarchical output.
func RenderTree(w io.Writer, root Node, children []Node) error {
	if err := RenderNode(w, root); err != nil {
		return err
	}
	sort.Slice(children, func(i, j int) bool { return children[i].QualifiedName < children[j].QualifiedName })
	for _, c := range children {
		if err := RenderNode(w, c); err != nil {
			return err
		}
	}
	return nil
}

// RenderJSON renders a single node as compact JSON. ExportJSON composes a list
// from it, making ExportJSON the second production caller of the rendering seam.
func RenderJSON(w io.Writer, n Node) error {
	_, err := fmt.Fprintf(w, "{\"id\":\"%s\",\"kind\":\"%s\",\"qn\":\"%s\"}", n.ID, n.Kind, n.QualifiedName)
	return err
}

// ExportJSON writes a JSON array of nodes by composing RenderJSON for each
// entry. It is the canonical export path and a direct caller of the seam.
func ExportJSON(w io.Writer, nodes []Node) error {
	if _, err := io.WriteString(w, "["); err != nil {
		return err
	}
	for i, n := range nodes {
		if i > 0 {
			if _, err := io.WriteString(w, ","); err != nil {
				return err
			}
		}
		if err := RenderJSON(w, n); err != nil {
			return err
		}
	}
	if _, err := io.WriteString(w, "]"); err != nil {
		return err
	}
	return nil
}

// RenderMarkdown renders a node as a markdown heading plus a metadata line.
func RenderMarkdown(w io.Writer, n Node) error {
	if _, err := fmt.Fprintf(w, "# %s\n_%s @ %s:%d_\n", n.QualifiedName, n.Kind, n.SourcePath, n.Line); err != nil {
		return err
	}
	return nil
}

