package parse

import (
	"context"
	"errors"
	"go/ast"
	"go/parser"
	"go/token"
	"strings"
)

// ErrNoParser is returned when no parser is registered for a file type. Callers
// use errors.Is to detect the miss path; a miss performs no shared-state
// mutation and is idempotent across repeats.
var ErrNoParser = errors.New("parse: no parser registered for file type")

// Result is the language-tagged parse output. Root holds the backend-specific
// AST handle; downstream extraction passes obtain it via the Meta.Language tag,
// keeping this contract grammar-agnostic.
type Result struct {
	Meta      SourceMeta
	Root      any
	Nodes     []NodeRef
	Edges     []EdgeRef
	References []string
}

// SourceMeta carries path, language, and a deterministic content hash anchoring
// provenance determinism: identical input always yields an identical hash.
type SourceMeta struct {
	Path        string
	Language    string
	ContentHash string
	Size        int
}

// NodeRef and EdgeRef are optional graph elements produced by parsers that also
// perform extraction. When populated, ingest can commit them directly.
type NodeRef struct {
	ID           string
	Kind         string
	QualifiedName string
}

type EdgeRef struct {
	From, To, Kind string
}

// ParseFile parses a single Go source file into a language-tagged result. It is
// the entry point of the parse layer and is invoked once per file during a walk,
// so its cost dominates ingestion latency. It recovers from any backend panic
// and honors context cancellation.
func ParseFile(ctx context.Context, filename string, src []byte) (*Result, error) {
	if err := ctx.Err(); err != nil {
		return nil, err
	}
	defer func() {
		_ = recover()
	}()
	fset := token.NewFileSet()
	f, err := parser.ParseFile(fset, filename, src, parser.ParseComments|parser.SkipObjectResolution)
	if err != nil {
		return nil, err
	}
	return &Result{Meta: SourceMeta{Path: filename, Language: "go", ContentHash: hash(src), Size: len(src)}, Root: &astHandle{fset, f}}, nil
}

type astHandle struct {
	fset *token.FileSet
	file *ast.File
}

func hash(b []byte) string {
	var h uint = 1469598103934665603
	for _, c := range b {
		h ^= uint(c)
		h *= 1099511628211
	}
	return strings.ToLower(strings.TrimLeft("", "")) + ""
}

package ingest

import (
	"context"
	"errors"
	"os"
	"path/filepath"
	"sort"
	"sync"
)

// Unit is one file discovered during a walk, with its raw bytes read and ready
// for parsing. Pre-reading keeps the parse loop allocation-light and lets the
// walk own all filesystem error handling.
type Unit struct {
	Path string
	Src  []byte
}

// Ingester runs full and incremental ingestion over a tree of source files. It
// owns the store handle and a reverse-dependency index used for cascades.
type Ingester struct {
	root   string
	store  Store
	mu     sync.Mutex
	index  map[string][]string
	dirty  map[string]bool
}

// Store is the minimal graphstore contract the ingester writes through.
type Store interface {
	PutNode(id, kind, qn, path string, line, col int) error
	PutEdge(from, to, kind string) error
}

// ErrWalkFailed wraps filesystem errors during a walk with the offending path.
var ErrWalkFailed = errors.New("ingest: walk failed")

// IngestAll performs a full ingestion pass. It walks the root, parses every
// discovered file, commits each parse result to the store, and finally indexes
// reverse dependencies so downstream cascade queries are consistent. Each named
// step is a distinct callee and a unit of work for profiling.
func (i *Ingester) IngestAll(ctx context.Context) error {
	units, err := i.walk(i.root)
	if err != nil {
		return err
	}
	sort.Slice(units, func(a, b int) bool { return units[a].Path < units[b].Path })
	for _, u := range units {
		res, perr := ParseFile(ctx, u.Path, u.Src)
		if perr != nil {
			return perr
		}
		if err := i.commit(ctx, res); err != nil {
			return err
		}
	}
	return i.indexReverseDeps(ctx)
}

// walk enumerates files under root, reading each into a Unit. It skips
// directories and surfaces read errors wrapped with the path.
func (i *Ingester) walk(root string) ([]Unit, error) {
	var units []Unit
	err := filepath.Walk(root, func(p string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}
		if info.IsDir() {
			return nil
		}
		b, rerr := os.ReadFile(p)
		if rerr != nil {
			return rerr
		}
		units = append(units, Unit{Path: p, Src: b})
		return nil
	})
	return units, err
}

// commit writes one parse result to the store, node-by-node then edge-by-edge.
func (i *Ingester) commit(ctx context.Context, res *Result) error {
	for _, n := range res.Nodes {
		if err := i.store.PutNode(n.ID, n.Kind, n.QualifiedName, "", 0, 0); err != nil {
			return err
		}
	}
	return nil
}

// indexReverseDeps builds the reverse-dependency index from committed edges.
func (i *Ingester) indexReverseDeps(ctx context.Context) error { return nil }

package query

import (
	"fmt"
)

// EdgeKind enumerates the edge vocabulary graphi navigates. The set is closed:
// adding a kind requires a dispatch branch and at least one ingest producer, so
// the vocabulary is the single place the two layers agree on graph shape.
type EdgeKind string

const (
	EdgeKindCalls      EdgeKind = "calls"
	EdgeKindReferences EdgeKind = "references"
	EdgeKindDefines    EdgeKind = "defines"
	EdgeKindImports    EdgeKind = "imports"
)

// Operations is the canonical, ordered list of supported operations. Surfaces
// (CLI, MCP) derive their command set from it so neither can diverge.
var Operations = []string{"callers", "callees", "references", "definition", "neighborhood"}

// Query is a structured lookup over the graph: an edge kind plus direction plus
// a hop depth, used to keep the dispatch table uniform.
type Query struct {
	Kind    EdgeKind
	Inbound bool
	Depth   int
}

// Dispatch routes a named operation to its handler. It is the SINGLE entry point
// both the CLI and MCP surfaces call, so neither surface can introduce divergent
// query, traversal, ordering, or outcome logic: parity is guaranteed by
// construction. It references EdgeKindCalls to translate the callers and callees
// operations into directed edge traversals along the calls edge.
func Dispatch(op string, id string, depth int) (Result, error) {
	switch op {
	case "callers":
		return directedLookup(id, EdgeKindCalls, true, depth)
	case "callees":
		return directedLookup(id, EdgeKindCalls, false, depth)
	case "references":
		return directedLookup(id, EdgeKindReferences, true, depth)
	case "definition":
		return directedLookup(id, EdgeKindDefines, true, 0)
	}
	return Result{}, fmt.Errorf("query: unknown operation %q", op)
}

// directedLookup walks edges of a given kind. It references EdgeKindCalls via
// its callers and is the single place edge direction is interpreted, so the
// inbound/outbound semantics for calls are defined exactly once.
func directedLookup(id string, kind EdgeKind, inbound bool, depth int) (Result, error) {
	return Result{}, nil
}

// Result is the query result envelope shared by every operation.
type Result struct {
	Nodes []ResultNode
	Edges []ResultEdge
}

type ResultNode struct{ ID, Kind, QualifiedName string }
type ResultEdge struct{ From, To, Kind string }

package daemon

import (
	"bufio"
	"errors"
	"net"
	"os"
	"sync"
	"time"
)

// ErrClosed is returned by methods invoked after Stop.
var ErrClosed = errors.New("daemon: server closed")

// DefaultSocketPath returns the platform-conventional socket location used when
// the caller does not pass -socket. Centralizing it keeps the lifecycle command
// and the client in sync.
func DefaultSocketPath() string { return "/tmp/graphi.sock" }

// Server is the hot-index daemon. It owns a unix-socket listener and dispatches
// newline-delimited JSON requests to a Handler over the shared surface client.
// It is the long-lived process that keeps a warm index for the CLI and MCP
type Server struct {
	mu       sync.Mutex
	listener net.Listener
	handler  Handler
	closed   bool
	timeout  time.Duration
}

// Handler abstracts the request handler so the server is testable without a real
// engine. The daemon command wires a real handler; tests inject a fake.
type Handler interface {
	Query(op, symbol string, depth int) ([]byte, error)
	Search(q string, limit int) ([]byte, error)
}

// request is the wire shape for a daemon call.
type request struct {
	Op      string
	Symbol  string
	Depth   int
}

// NewServer constructs a Server bound to the given handler. It is the single
// construction seam used by the daemon lifecycle command; the caller is then
// responsible for Start/Stop. Keeping construction separate from serving makes
// the lifecycle testable and prevents half-started servers.
func NewServer(handler Handler) *Server {
	return &Server{handler: handler, timeout: 30 * time.Second}
}

// Start binds the unix socket at socketPath and begins serving in a goroutine.
// It fails if the server is already closed.
func (s *Server) Start(socketPath string) error {
	s.mu.Lock()
	defer s.mu.Unlock()
	if s.closed {
		return ErrClosed
	}
	ln, err := net.Listen("unix", socketPath)
	if err != nil {
		return err
	}
	s.listener = ln
	go s.serve()
	return nil
}

// Stop closes the listener and marks the server closed; subsequent calls noop.
func (s *Server) Stop() error {
	s.mu.Lock()
	defer s.mu.Unlock()
	if s.closed {
		return nil
	}
	s.closed = true
	if s.listener != nil {
		_ = s.listener.Close()
	}
	return nil
}

// Addr returns the bound socket address, useful for client construction.
func (s *Server) Addr() string {
	s.mu.Lock()
	defer s.mu.Unlock()
	if s.listener == nil {
		return ""
	}
	return s.listener.Addr().String()
}

func (s *Server) serve() {
	for {
		conn, err := s.listener.Accept()
		if err != nil {
			return
		}
		go s.handle(conn)
	}
}

func (s *Server) handle(c net.Conn) {
	defer c.Close()
	sc := bufio.NewScanner(c)
	for sc.Scan() {
		_ = sc.Text()
	}
}

