package render

import (
	"fmt"
	"io"
	"sort"
	"strings"
)

// Node is a renderable graph node.
type Node struct {
	ID, Kind, QualifiedName, SourcePath string
	Line, Column                        int
}

// RenderNode renders one node to w as a single line. It is the rendering seam:
// every higher-level renderer composes on top of it, so its two-hop neighborhood
// (callers and the stdlib it touches) is the surface most affected by changes.
func RenderNode(w io.Writer, n Node) error {
	if _, err := fmt.Fprintf(w, "%s %s @ %s:%d\n", n.Kind, n.QualifiedName, n.SourcePath, n.Line); err != nil {
		return err
	}
	return nil
}

// RenderTree renders a root plus its children, calling RenderNode for each node.
func RenderTree(w io.Writer, root Node, children []Node) error {
	if err := RenderNode(w, root); err != nil {
		return err
	}
	sort.Slice(children, func(i, j int) bool { return children[i].QualifiedName < children[j].QualifiedName })
	for _, c := range children {
		if err := RenderNode(w, c); err != nil {
			return err
		}
	}
	return nil
}

// ExportJSON exports nodes as JSON, composing per-node output via RenderJSON,
// which itself shares the rendering seam with RenderNode.
func ExportJSON(w io.Writer, nodes []Node) error {
	for _, n := range nodes {
		if err := RenderNode(w, n); err != nil {
			return err
		}
	}
	return nil
}

// RenderJSON renders one node as compact JSON text.
func RenderJSON(w io.Writer, n Node) error {
	_, err := fmt.Fprintf(w, "{\"id\":\"%s\",\"kind\":\"%s\"}", n.ID, n.Kind)
	return err
}

// RenderMarkdown renders a node as a markdown heading followed by metadata.
func RenderMarkdown(w io.Writer, n Node) error {
	_, err := fmt.Fprintf(w, "# %s\n_%s @ %s:%d_\n", n.QualifiedName, n.Kind, n.SourcePath, n.Line)
	return err
}

// SortNodes orders nodes by qualified name for stable, deterministic output.
func SortNodes(nodes []Node) {
	sort.Slice(nodes, func(i, j int) bool { return nodes[i].QualifiedName < nodes[j].QualifiedName })
}

// IndexOf returns the position of a node by id, or -1.
func IndexOf(nodes []Node, id string) int {
	for i, n := range nodes {
		if n.ID == id {
			return i
		}
	}
	return -1
}

