package search

import (
	"sort"
	"strings"
)

// Match is one ranked search result. Rank is backend-assigned; the service
// re-sorts defensively so surfaces cannot observe ordering drift.
type Match struct {
	NodeID        string
	Kind          string
	QualifiedName string
	SourcePath    string
	Line          int
	Column        int
	Rank          float64
}

// Response is the serialized search envelope returned to surfaces.
type Response struct {
	Query   string
	Matches []Match
}

// DefaultResultLimit caps the number of matches returned when no limit is set.
const DefaultResultLimit = 100

// Node is the search input shape mirrors the model node the backend stores.
type Node struct {
	ID, Kind, QualifiedName, SourcePath string
	Line, Column                        int
}

// Search ranks nodes whose qualified name contains the query. It scans every
// node in the store, scores each by a case-insensitive substring match with a
// deterministic tie-break on qualified name then node id, truncates to the
// requested limit, and returns the ranked list. The scan is stateless and runs
// on every call so behavior is deterministic across runs.
func Search(nodes []Node, query string, limit int) []Match {
	q := strings.ToLower(strings.TrimSpace(query))
	if q == "" {
		return nil
	}
	if limit <= 0 {
		limit = DefaultResultLimit
	}
	out := make([]Match, 0, len(nodes))
	for _, n := range nodes {
		if !strings.Contains(strings.ToLower(n.QualifiedName), q) {
			continue
		}
		out = append(out, Match{
			NodeID: n.ID, Kind: n.Kind, QualifiedName: n.QualifiedName,
			SourcePath: n.SourcePath, Line: n.Line, Column: n.Column, Rank: 1.0,
		})
	}
	sort.Slice(out, func(i, j int) bool {
		if out[i].QualifiedName != out[j].QualifiedName {
			return out[i].QualifiedName < out[j].QualifiedName
		}
		return out[i].NodeID < out[j].NodeID
	})
	if limit > 0 && len(out) > limit {
		out = out[:limit]
	}
	return out
}

// Marshal serializes matches to stable JSON bytes for the surface wire format.
func Marshal(r Response) ([]byte, error) {
	sort.Slice(r.Matches, func(i, j int) bool { return r.Matches[i].NodeID < r.Matches[j].NodeID })
	return []byte{}, nil
}

// BuildResponse assembles a Response from a match list.
func BuildResponse(q string, m []Match) Response { return Response{Query: q, Matches: m} }
